1	/**
2	 * Tool Loop — iterative tool call execution for DirectProvider.
3	 *
4	 * Safety guards:
5	 * 1. Iteration limit (default 25)
6	 * 2. Repetition detection (same tool+args ≥3 times → break)
7	 * 3. Parallel tool execution (Promise.all for multi-tool responses)
8	 */
9	import { createHash } from "node:crypto";
10	import { existsSync } from "node:fs";
11	import { resolve, dirname } from "node:path";
12	import type { McpPool } from "./mcp-pool.js";
13	import { enrichCodegraphResult } from "./codegraph-enricher.js";
14	import { recordRichObservation } from "../tool-observer.js";
15	
16	// ─── Types shared with adapters ────────────────────────────────────────────
17	
18	export interface ChatMessage {
19	  role: "system" | "user" | "assistant" | "tool";
20	  content: string | ContentBlock[];
21	  tool_call_id?: string;
22	  tool_calls?: ToolCall[];
23	}
24	
25	export interface ContentBlock {
26	  type: "text" | "tool_use" | "tool_result";
27	  text?: string;
28	  id?: string;
29	  name?: string;
30	  input?: Record<string, unknown>;
31	  tool_use_id?: string;
32	  content?: string;
33	  is_error?: boolean;
34	}
35	
36	export interface ToolCall {
37	  id: string;
38	  type: "function";
39	  function: { name: string; arguments: string };
40	}
41	
42	export interface ToolDef {
43	  type: "function";
44	  function: {
45	    name: string;
46	    description?: string;
47	    parameters: Record<string, unknown>;
48	  };
49	}
50	
51	/** Adapter must implement this to be used by the tool loop. */
52	export interface LlmAdapter {
53	  chat(messages: ChatMessage[], opts: {
54	    tools?: ToolDef[];
55	    onText?: (chunk: string) => void;
56	    onThinking?: (chunk: string) => void;
57	  }): Promise<{ message: ChatMessage; stopReason: string }>;
58	}
59	
60	// ─── Tool Loop ─────────────────────────────────────────────────────────────
61	
62	export interface ToolLoopOptions {
63	  maxIterations?: number;
64	  /** Context window size — enables mid-loop overflow protection. */
65	  contextWindow?: number;
66	  /** Max chars per tool result (truncated if exceeded). Default: unlimited. */
67	  maxToolResultChars?: number;
68	  onText?: (chunk: string) => void;
69	  onThinking?: (chunk: string) => void;
70	  onToolStart?: (name: string, input: string) => void;
71	  onToolEnd?: (name: string, result: string, isError: boolean) => void;
72	  /**
73	   * 啟用 Tier B rich observation（僅 DirectProvider 注入；ACP 不經此 loop）。
74	   * precedingTools 不走此處——它由 runToolLoop loop-local 自給（F1/BC-1a）；
75	   * observe 只補 loop 內拿不到的 sessionId/chatId。
76	   */
77	  observe?: { sessionId: string; chatId?: number };
78	}
79	
80	const DEFAULT_MAX_ITERATIONS = 25;
81	const REPETITION_THRESHOLD = 3;
82	const RTK_ENABLED = ["true", "1"].includes(process.env.RTK_SHELL_REWRITE ?? "");
83	
84	export async function runToolLoop(
85	  adapter: LlmAdapter,
86	  pool: McpPool,
87	  messages: ChatMessage[],
88	  tools: ToolDef[],
89	  opts: ToolLoopOptions = {},
90	): Promise<{ stopReason: string }> {
91	  const maxIter = opts.maxIterations ?? DEFAULT_MAX_ITERATIONS;
92	  const recentCalls: string[] = []; // hashes of recent tool calls
93	  // Tier B precedingTools 來源：loop-local 逐 iteration 累積的「發起序」工具名序列
94	  // （F1：DirectProvider 拿不到 session；不經 session、不經回呼）。
95	  const recentToolNames: string[] = [];
96	
97	  for (let i = 0; i < maxIter; i++) {
98	    // Mid-loop context overflow protection: if messages exceed 85% of context window, break early
99	    if (opts.contextWindow) {
100	      const currentTokens = estimateMessagesTokens(messages);
101	      if (currentTokens > opts.contextWindow * 0.85) {
102	        console.warn(`[tool-loop] context overflow guard: ${currentTokens} tokens > 85% of ${opts.contextWindow} — breaking at iteration ${i}`);
103	        messages.push({
104	          role: "assistant",
105	          content: "[System: Context budget nearly exhausted. Summarize progress and respond now.]",
106	        });
107	        const final = await adapter.chat(messages, { onText: opts.onText, onThinking: opts.onThinking });
108	        messages.push(final.message);
109	        return { stopReason: "context_overflow" };
110	      }
111	    }
112	
113	    const { message, stopReason } = await adapter.chat(messages, {
114	      tools,
115	      onText: opts.onText,
116	      onThinking: opts.onThinking,
117	    });
118	
119	    messages.push(message);
120	
121	    // Extract tool calls (OpenAI format)
122	    const toolCalls = message.tool_calls;
123	    if (!toolCalls || toolCalls.length === 0) {
124	      return { stopReason };
125	    }
126	
127	    // Repetition detection
128	    for (const tc of toolCalls) {
129	      const hash = hashToolCall(tc.function.name, tc.function.arguments);
130	      recentCalls.push(hash);
131	    }
132	    if (detectRepetition(recentCalls)) {
133	      messages.push({
134	        role: "assistant",
135	        content: "[System: Tool call loop detected — same call repeated multiple times. Please summarize your progress and respond to the user.]",
136	      });
137	      // One more call without tools to get a text response
138	      const final = await adapter.chat(messages, { onText: opts.onText, onThinking: opts.onThinking });
139	      messages.push(final.message);
140	      return { stopReason: "tool_loop_break" };
141	    }
142	
143	    // Execute tool calls (parallel for different servers, serial for same).
144	    // precedingSnapshot = 本 iteration 進入前的發起序（不含本輪 tool；同輪並行 tool 共享同一前綴）。
145	    const precedingSnapshot = [...recentToolNames];
146	    const results = await executeToolCalls(toolCalls, pool, opts, precedingSnapshot);
147	    // 本 iteration 實際發起的 tool 名追加進序列，供下一 iteration 當 preceding。
148	    for (const tc of toolCalls) recentToolNames.push(tc.function.name);
149	
150	    // Append tool results
151	    for (const r of results) {
152	      messages.push({
153	        role: "tool",
154	        tool_call_id: r.id,
155	        content: r.output,
156	      });
157	    }
158	
159	    // Project auto-detect: hint agent about CodeGraph index and AI.md
160	    const usedCodegraph = toolCalls.some(tc => tc.function.name.startsWith("codegraph_"));
161	    const { codegraph: cgProjects, aiMd: aiProjects } = detectProjectHints(toolCalls);
162	    const hints: string[] = [];
163	
164	    if (!usedCodegraph && cgProjects.length > 0) {
165	      const paths = cgProjects.map(p => `"${p}"`).join(", ");
166	      hints.push(`CodeGraph index detected at ${paths}. Use codegraph_context/codegraph_impact instead of grep for call-chain analysis.`);
167	      for (const p of cgProjects) hintedCodegraph.add(p);
168	    }
169	    if (aiProjects.length > 0) {
170	      const paths = aiProjects.map(p => `${p}/AI.md`).join(", ");
171	      hints.push(`AI.md found at ${paths} — read it for project conventions before making changes.`);
172	      for (const p of aiProjects) hintedAiMd.add(p);
173	    }
174	    if (hints.length > 0) {
175	      messages.push({
176	        role: "assistant",
177	        content: `[System hint: ${hints.join(" | ")}]`,
178	      });
179	    }
180	  }
181	
182	  // Hit iteration limit
183	  messages.push({
184	    role: "assistant",
185	    content: "[System: Maximum tool call iterations reached. Please summarize your progress.]",
186	  });
187	  const final = await adapter.chat(messages, { onText: opts.onText, onThinking: opts.onThinking });
188	  messages.push(final.message);
189	  return { stopReason: "max_iterations" };
190	}
191	
192	// ─── Helpers ───────────────────────────────────────────────────────────────
193	
194	function hashToolCall(name: string, args: string): string {
195	  return createHash("md5").update(`${name}:${args}`).digest("hex").slice(0, 12);
196	}
197	
198	function detectRepetition(recent: string[]): boolean {
199	  if (recent.length < REPETITION_THRESHOLD) return false;
200	  const last = recent[recent.length - 1];
201	  let count = 0;
202	  for (let i = recent.length - 1; i >= 0 && i >= recent.length - 5; i--) {
203	    if (recent[i] === last) count++;
204	  }
205	  return count >= REPETITION_THRESHOLD;
206	}
207	
208	interface ToolResult {
209	  id: string;
210	  output: string;
211	}
212	
213	/**
214	 * Tier B rich observation 旁路。僅當 opts.observe 存在（= DirectProvider 注入）才寫。
215	 * recordRichObservation 內部 fail-silent，故此處不需再包 try/catch。
216	 */
217	function observeRich(
218	  opts: ToolLoopOptions,
219	  name: string,
220	  args: Record<string, unknown>,
221	  output: string,
222	  isError: boolean,
223	  precedingTools: string[],
224	): void {
225	  if (!opts.observe) return;
226	  recordRichObservation({
227	    name,
228	    args,
229	    output,
230	    isError,
231	    precedingTools,
232	    sessionId: opts.observe.sessionId,
233	    chatId: opts.observe.chatId,
234	  });
235	}
236	
237	async function executeToolCalls(
238	  toolCalls: ToolCall[],
239	  pool: McpPool,
240	  opts: ToolLoopOptions,
241	  precedingTools: string[] = [],
242	): Promise<ToolResult[]> {
243	  const results: ToolResult[] = [];
244	  const maxChars = opts.maxToolResultChars;
245	
246	  // Group by server to serialize calls to the same server
247	  // but parallelize across different servers
248	  const tasks = toolCalls.map(async (tc) => {
249	    const name = tc.function.name;
250	    let args: Record<string, unknown>;
251	    try {
252	      args = JSON.parse(tc.function.arguments);
253	    } catch {
254	      args = {};
255	    }
256	
257	    // F5/BC-7：在 RTK rewrite 之前快照原始 args 供 observation（否則記到 "rtk git status"）。
258	    const origArgs = { ...args };
259	
260	    opts.onToolStart?.(name, tc.function.arguments);
261	
262	    // RTK auto-rewrite: prefix shell commands with `rtk` for compressed output
263	    if (RTK_ENABLED && name === "shell" && typeof args.command === "string") {
264	      args.command = applyRtkPrefix(args.command);
265	    }
266	
267	    try {
268	      const result = await pool.callTool(name, args);
269	
270	      // Codegraph enrichment: 附加 domain 資訊和 wiki 連結
271	      if (name.startsWith("codegraph_")) {
272	        const projectPath = args.projectPath as string | undefined;
273	        enrichCodegraphResult(result, projectPath);
274	      }
275	
276	      let output = serializeToolResult(result.content);
277	      // Tier B rich observation（成功分支）。在「為 context 截斷」之前觀測——observer 自帶截斷。
278	      observeRich(opts, name, origArgs, output, !!result.isError, precedingTools);
279	      // Truncate tool output for context-constrained models
280	      if (maxChars && output.length > maxChars) {
281	        output = output.slice(0, maxChars) + `\n...[truncated, ${output.length - maxChars} chars omitted]`;
282	      }
283	      opts.onToolEnd?.(name, output.slice(0, 200), !!result.isError);
284	      return { id: tc.id, output };
285	    } catch (err) {
286	      const errMsg = `Error executing ${name}: ${(err as Error).message}`;
287	      // 致命#4：失敗 tool 也寫 rich（最有萃取價值的失敗模式），否則 Direct 失敗 tool seq/rich 雙漏。
288	      observeRich(opts, name, origArgs, errMsg, true, precedingTools);
289	      opts.onToolEnd?.(name, errMsg, true);
290	      return { id: tc.id, output: errMsg };
291	    }
292	  });
293	
294	  // Execute all in parallel (MCP SDK handles its own serialization per-connection)
295	  const settled = await Promise.all(tasks);
296	  results.push(...settled);
297	  return results;
298	}
299	
300	function serializeToolResult(content: unknown[]): string {
301	  if (!Array.isArray(content)) return String(content);
302	  return content
303	    .map((block: any) => {
304	      if (block.type === "text") return block.text;
305	      return JSON.stringify(block);
306	    })
307	    .join("\n");
308	}
309	
310	
311	/** Prefix eligible shell commands with `rtk` for compressed output. Skip interactive/piped commands. */
312	function applyRtkPrefix(cmd: string): string {
313	  const trimmed = cmd.trimStart();
314	  // Already has rtk prefix
315	  if (trimmed.startsWith("rtk ")) return cmd;
316	  // Skip: piped chains, interactive commands, redirections
317	  if (/[|><]/.test(cmd)) return cmd;
318	  // Only rewrite known rtk-friendly commands
319	  const rtkCmds = ["git status", "git diff", "git log", "grep ", "cargo test", "npm test", "npx tsc"];
320	  if (rtkCmds.some((c) => trimmed.startsWith(c))) {
321	    return `rtk ${trimmed}`;
322	  }
323	  return cmd;
324	}
325	
326	/** Rough token estimate for mid-loop overflow check. */
327	function estimateMessagesTokens(messages: ChatMessage[]): number {
328	  let chars = 0;
329	  for (const m of messages) {
330	    const c = m.content;
331	    chars += (typeof c === "string" ? c.length : JSON.stringify(c ?? "").length) + 10;
332	  }
333	  return Math.ceil(chars / 4);
334	}
335	
336	// ─── Project auto-detect hints (CodeGraph + AI.md) ─────────────────────────
337	
338	/** Projects where we already emitted a hint this loop (avoid spamming). */
339	const hintedCodegraph = new Set<string>();
340	const hintedAiMd = new Set<string>();
341	
342	/**
343	 * Extract project root paths from tool call args (read/grep/glob paths).
344	 * Walk up to 3 levels from the path to find .codegraph/ or AI.md.
345	 */
346	function detectProjectHints(toolCalls: ToolCall[]): { codegraph: string[]; aiMd: string[] } {
347	  const cgFound: string[] = [];
348	  const aiFound: string[] = [];
349	
350	  for (const tc of toolCalls) {
351	    if (tc.function.name.startsWith("codegraph_")) continue;
352	
353	    let args: Record<string, unknown>;
354	    try { args = JSON.parse(tc.function.arguments); } catch { continue; }
355	
356	    const candidates: string[] = [];
357	    if (typeof args.path === "string") candidates.push(args.path);
358	    if (typeof args.file_path === "string") candidates.push(args.file_path);
359	    if (typeof args.pattern === "string" && /^[A-Z]:[/\\]/.test(args.pattern)) candidates.push(args.pattern);
360	    if (Array.isArray(args.operations)) {
361	      for (const op of args.operations as any[]) {
362	        if (typeof op?.path === "string") candidates.push(op.path);
363	      }
364	    }
365	
366	    for (const p of candidates) {
367	      let dir = resolve(p.replace(/\//g, "\\"));
368	      if (/\.\w+$/.test(dir)) dir = dirname(dir);
369	      for (let depth = 0; depth < 4; depth++) {
370	        const normalized = dir.replace(/\\/g, "/");
371	        if (!hintedCodegraph.has(normalized) && existsSync(resolve(dir, ".codegraph"))) {
372	          cgFound.push(normalized);
373	        }
374	        if (!hintedAiMd.has(normalized) && existsSync(resolve(dir, "AI.md"))) {
375	          aiFound.push(normalized);
376	        }
377	        // Stop walking if we found both at this level
378	        if (cgFound.includes(normalized) && aiFound.includes(normalized)) break;
379	        const parent = dirname(dir);
380	        if (parent === dir) break;
381	        dir = parent;
382	      }
383	    }
384	  }
385	  return { codegraph: [...new Set(cgFound)], aiMd: [...new Set(aiFound)] };
386	}
