237	async function executeToolCalls(
238	  toolCalls: ToolCall[],
239	  pool: McpPool,
240	  opts: ToolLoopOptions,
241	  precedingTools: string[] = [],
242	): Promise<ToolResult[]> {
243	  const results: ToolResult[] = [];
244	  const maxChars = opts.maxToolResultChars;
245	
246	  // Group by server to serialize calls to the same server
247	  // but parallelize across different servers
248	  const tasks = toolCalls.map(async (tc) => {
249	    const name = tc.function.name;
250	    let args: Record<string, unknown>;
251	    try {
252	      args = JSON.parse(tc.function.arguments);
253	    } catch {
254	      args = {};
255	    }
256	
257	    // F5/BC-7：在 RTK rewrite 之前快照原始 args 供 observation（否則記到 "rtk git status"）。
258	    const origArgs = { ...args };
259	
260	    opts.onToolStart?.(name, tc.function.arguments);
261	
262	    // RTK auto-rewrite: prefix shell commands with `rtk` for compressed output
263	    if (RTK_ENABLED && name === "shell" && typeof args.command === "string") {
264	      args.command = applyRtkPrefix(args.command);
265	    }
266	
267	    try {
268	      const result = await pool.callTool(name, args);
269	
270	      // Codegraph enrichment: 附加 domain 資訊和 wiki 連結
271	      if (name.startsWith("codegraph_")) {
272	        const projectPath = args.projectPath as string | undefined;
273	        enrichCodegraphResult(result, projectPath);
274	      }
275	
276	      let output = serializeToolResult(result.content);
277	      // Tier B rich observation（成功分支）。在「為 context 截斷」之前觀測——observer 自帶截斷。
278	      observeRich(opts, name, origArgs, output, !!result.isError, precedingTools);
279	      // Truncate tool output for context-constrained models
280	      if (maxChars && output.length > maxChars) {
281	        output = output.slice(0, maxChars) + `\n...[truncated, ${output.length - maxChars} chars omitted]`;
282	      }
283	      opts.onToolEnd?.(name, output.slice(0, 200), !!result.isError);
284	      return { id: tc.id, output };
285	    } catch (err) {
286	      const errMsg = `Error executing ${name}: ${(err as Error).message}`;
287	      // 致命#4：失敗 tool 也寫 rich（最有萃取價值的失敗模式），否則 Direct 失敗 tool seq/rich 雙漏。
288	      observeRich(opts, name, origArgs, errMsg, true, precedingTools);
289	      opts.onToolEnd?.(name, errMsg, true);
290	      return { id: tc.id, output: errMsg };
291	    }
292	  });
